"use strict";const t=require("../common/vendor.js").defineStore("dispute",{state:()=>({disputeList:[],currentDispute:null,loading:!1,page:1,pageSize:10,hasMore:!0}),getters:{pendingAssignCount:t=>t.disputeList.filter((t=>"待分派"===t.status)).length,pendingVisitCount:t=>t.disputeList.filter((t=>"待回访"===t.status)).length,resolvedCount:t=>t.disputeList.filter((t=>"已化解"===t.status)).length,todayNewCount:t=>{const e=(new Date).toISOString().split("T")[0];return t.disputeList.filter((t=>new Date(t.create_time).toISOString().split("T")[0]===e)).length}},actions:{setDisputeList(t){this.disputeList=t},addDispute(t){this.disputeList.unshift(t)},updateDispute(t,e){const s=this.disputeList.findIndex((e=>e._id===t));-1!==s&&(this.disputeList[s]={...this.disputeList[s],...e}),this.currentDispute&&this.currentDispute._id===t&&(this.currentDispute={...this.currentDispute,...e})},setCurrentDispute(t){this.currentDispute=t},resetPage(){this.page=1,this.hasMore=!0},loadMore(){this.hasMore&&!this.loading&&this.page++}}});exports.useDisputeStore=t;
